diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 658bbbc569766..bbdbb3a208ded 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2808,8 +2808,14 @@ static Instruction *foldFNegIntoConstant(Instruction &I, const DataLayout &DL) {
   // Fold negation into constant operand.
   // -(X * C) --> X * (-C)
   if (match(FNegOp, m_FMul(m_Value(X), m_Constant(C))))
-    if (Constant *NegC = ConstantFoldUnaryOpOperand(Instruction::FNeg, C, DL))
-      return BinaryOperator::CreateFMulFMF(X, NegC, &I);
+    if (Constant *NegC = ConstantFoldUnaryOpOperand(Instruction::FNeg, C, DL)) {
+      FastMathFlags FNegF = I.getFastMathFlags();
+      FastMathFlags OpF = FNegOp->getFastMathFlags();
+      FastMathFlags FMF = FastMathFlags::unionValue(FNegF, OpF) |
+                          FastMathFlags::intersectRewrite(FNegF, OpF);
+      FMF.setNoInfs(FNegF.noInfs() && OpF.noInfs());
+      return BinaryOperator::CreateFMulFMF(X, NegC, FMF);
+    }
   // -(X / C) --> X / (-C)
   if (match(FNegOp, m_FDiv(m_Value(X), m_Constant(C))))
     if (Constant *NegC = ConstantFoldUnaryOpOperand(Instruction::FNeg, C, DL))

tests.source_program:
define float @fmul_fneg(float %x) {
  %m = fmul float %x, 4.200000e+01
  %r = fneg float %m
  ret float %r
}

define float @fmul_fneg_fmf(float %x) {
  %m = fmul float %x, 4.200000e+01
  %r = fneg reassoc nsz float %m
  ret float %r
}

define float @fmul_fsub_fmf(float %x) {
  %m = fmul float %x, 4.200000e+01
  %r = fsub reassoc nsz float -0.000000e+00, %m
  ret float %r
}

define float @test_fneg_ninf_mul_with_anyzero(float %a) {
  %mul = fmul float %a, 0.000000e+00
  %f = fneg ninf float %mul
  ret float %f
}

define float @test_fneg_nnan_mul_with_anyzero(float %a) {
  %f1 = fmul float %a, 0.000000e+00
  %f2 = fneg nnan float %f1
  ret float %f2
}

define float @test_fneg_nsz_mul_with_anyzero(float %a) {
  %f1 = fmul float %a, 0.000000e+00
  %f2 = fneg nsz float %f1
  ret float %f2
}

define <vscale x 2 x double> @test_fneg_select_svec_3(<vscale x 2 x i1> %cond, <vscale x 2 x double> %b) {
  %1 = select <vscale x 2 x i1> %cond, <vscale x 2 x double> zeroinitializer, <vscale x 2 x double> zeroinitializer
  %2 = fneg fast <vscale x 2 x double> %1
  ret <vscale x 2 x double> %2
}

define float @test_fsub_ninf_mul_with_anyzero(float %a) {
  %f1 = fmul float %a, 0.000000e+00
  %f2 = fsub ninf float -0.000000e+00, %f1
  ret float %f2
}

define float @sub_add_neg_x(float %x, float %y) {
  %mul = fmul float %x, 5.000000e+00
  %add = fadd float %mul, %y
  %r = fsub reassoc nsz float %y, %add
  ret float %r
}

define float @sub_sub_nsz(float %x, float %y, float %z) {
  %t1 = fsub float %x, %y
  %t2 = fsub nsz float %z, %t1
  ret float %t2
}
